    arr = np.array(grid)

    # Iterate over each row
    for i in range(arr.shape[0]):
        # Count non-zero elements excluding the third position
        count_non_zero_excluding_third = np.sum(arr[i] != 0) - (arr[i][2] != 0)

        # Set the third position to 2 if the count is odd, otherwise keep it as 0
