def solve(grid):
    arr = np.array(grid)
    rows, cols = arr.shape

    # Identify positions of '5'
    fives = np.argwhere(arr == 5)

    for row, col in fives:
        if row > 0 and arr[row-1, col] == 1:
            arr[row-1, col] = 2
        if row < rows - 1 and arr[row+1, col] == 1:
            arr[row+1, col] = 2
        if col > 0 and arr[row, col-1] == 1:
            arr[row, col-1] = 2
        if col < cols - 1 and arr[row, col+1] == 1:
            arr[row, col+1] = 2

    arr[arr == 1] = 0
    return arr.tolist()

