    # Find the minimum non-zero value in each column
    min_non_zero_cols = np.minimum.reduceat(arr.T[arr.T != 0], np.arange(0, arr.shape[1] + 1) * arr.shape[0])

    # Replace non-zero values in rows with the corresponding minimum non-zero value
    for i in range(arr.shape[0]):
        if arr[i, :].any():
            mask = arr[i, :] != 0
            arr[i, mask] = min_non_zero_rows[i]

